import sys

n = int(sys.stdin.readline())

max_price = n * 2 - 1
nines = 0
mp = max_price
while mp >= 9:
    nines += 1
    mp = mp // 10
if nines < 1:
    print(n * (n - 1) // 2)
    exit()

price_suffix = "9" * nines
total_pairs = 0

for d in range(0, 10):
    if d > 0:
        price = int(str(d) + price_suffix)
    else:
        price = int(price_suffix)
    if price > max_price:
        continue
    half = price // 2
    if price % 2 == 0:
        pairs = min(half - 1, n - half)
        if pairs >= 0:
            total_pairs += pairs + 1
    else:
        pairs = min(half, n - half)
        if pairs >= 0:
            total_pairs += pairs

print(total_pairs)
